function slugify(value) {
  return value.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/(^-|-$)/g, '');
}

function buildDiseaseEntry([name, category, alternativeName, symptoms, causes, riskFactors, prevention, diagnosis, treatment, homeCare, lifestyle, complications, prognosis], index) {
  const slug = slugify(name);
  return {
    id: index + 1,
    slug,
    name,
    category,
    alternativeNames: [alternativeName],
    icdCode: [],
    overview: `${name} is a ${category.toLowerCase()} condition that can affect health, comfort, and daily function. It is commonly managed with a combination of medical care, symptom control, and long-term lifestyle support.`,
    definition: `${name} is a medical condition that requires careful evaluation and appropriate treatment. Early recognition and consistent management can improve symptoms and reduce complications.`,
    symptoms,
    causes,
    riskFactors,
    prevention,
    diagnosis,
    treatment,
    homeCare,
    lifestyle,
    complications,
    prognosis,
    faq: [
      {
        question: `What are the common signs of ${name}?`,
        answer: `Common signs often include ${symptoms.slice(0, 3).join(', ')}. A clinician can help confirm the diagnosis and guide appropriate treatment.`
      },
      {
        question: `How is ${name} usually managed?`,
        answer: `Management often combines evaluation, treatment of the underlying cause, and support for daily symptoms. The exact plan depends on severity and individual health factors.`
      }
    ],
    relatedDiseases: [
      category === 'Respiratory' ? 'Asthma' : category === 'Cardiology' ? 'Hypertension' : category === 'Neurology' ? 'Migraine' : category === 'Endocrinology' ? 'Diabetes Mellitus' : category === 'Gastroenterology' ? 'Irritable Bowel Syndrome' : category === 'Dermatology' ? 'Eczema' : category === 'Rheumatology' ? 'Osteoarthritis' : category === 'Nephrology' || category === 'Urology' ? 'Urinary Tract Infection' : category === 'Hematology' ? 'Anemia' : category === 'Psychiatry' ? 'Anxiety Disorder' : 'Glaucoma'
    ],
    relatedSymptoms: symptoms.slice(0, 4),
    medicalReferences: ['World Health Organization', 'National Institutes of Health'],
    lastReviewed: '2026-06-01',
    seoTitle: `${name} Symptoms, Causes, and Treatment`,
    seoDescription: `Learn about ${name}, including symptoms, causes, diagnosis, treatment, prevention, and when to seek medical care.`,
    tags: [category.toLowerCase(), slug, 'medical knowledge'],
    sections: {
      overview: `${name} is a clinically important condition that can affect comfort, function, and long-term health. Understanding the condition helps people seek timely care and make informed decisions.`,
      definition: `${name} is a medical condition with recognizable signs and risks. It may be acute, chronic, or progressive depending on the underlying cause.`,
      symptoms,
      causes,
      riskFactors,
      prevention,
      diagnosis,
      treatments: treatment,
      homeCare,
      lifestyle,
      complications,
      prognosis,
      faq: [
        {
          question: `What are the common signs of ${name}?`,
          answer: `Common signs often include ${symptoms.slice(0, 3).join(', ')}. A clinician can help confirm the diagnosis and guide appropriate treatment.`
        },
        {
          question: `How is ${name} usually managed?`,
          answer: `Management often combines evaluation, treatment of the underlying cause, and support for daily symptoms. The exact plan depends on severity and individual health factors.`
        }
      ],
      references: ['World Health Organization', 'National Institutes of Health']
    }
  };
}

const prepared = diseases.map(buildDiseaseEntry);
fs.mkdirSync(path.dirname(outputPath), { recursive: true });
fs.writeFileSync(outputPath, JSON.stringify(prepared, null, 2));
console.log(`Generated ${prepared.length} disease records at ${outputPath}`);
